content:
{
  "sentences": [
    {
      "text": "你好，我想要一杯小杯的拿鐵，可以嗎？",
      "pinyin": "Nǐ hǎo, wǒ xiǎng yào yī bēi xiǎo bēi de nátiě, kěyǐ ma?",
      "pinyin_numeric": "ni3 hao3, wo3 xiang3 yao4 yi1 bei1 xiao3 bei1 de1 na2tie3, ke3yi3 ma0?",
      "translation_en": "Hello, I would like a small latte, okay?",
      "translation_ko": "안녕하세요, 작은 라떼 한 잔을 원하는데 괜찮을까요?"
    },
    {
      "text": "麻煩你，可以給我半糖的紅茶嗎？",
      "pinyin": "Máfan nǐ, kěyǐ gěi wǒ bàn táng de hóngchá ma?",
      "pinyin_numeric": "ma2fan2 ni3, ke3yi3 gei3 wo3 ban4 tang2 de1 hong2cha2 ma0?",
      "translation_en": "Excuse me, could you give me a half-sugar black tea?",
      "translation_ko": "실례합니다, 반당 홍차를 주실 수 있나요?"
    },
    {
      "text": "不好意思，可以幫我換成去冰的綠茶嗎？",
      "pinyin": "Bù hǎo yìsi, kěyǐ bāng wǒ huàn chéng qù bīng de lǜchá ma?",
      "pinyin_numeric": "bu4 hao3 yi4si0, ke3yi3 bang1 wo3 huan4 cheng2 qu4 bing1 de1 lü4cha2 ma0?",
      "translation_en": "Excuse me, could you help me change it to an iced green tea without ice?",
      "translation_ko": "죄송합니다, 얼음 없는 녹차로 바꿔 주실 수 있나요?"
    },
    {
      "text": "店員，可以給我一個袋子嗎？",
      "pinyin": "Diànyuán, kěyǐ gěi wǒ yī ge dàizi ma?",
      "pinyin_numeric": "dian4yuan2, ke3yi3 gei3 wo3 yi1 ge0 dai4zi0 ma0?",
      "translation_en": "Shop assistant, could you give me a bag?",
      "translation_ko": "점원님, 봉투 하나 주실 수 있나요?"
    },
    {
      "text": "客人，可以等一下嗎？我幫你準備。",
      "pinyin": "Kèrén, kěyǐ děng yīxià ma? Wǒ bāng nǐ zhǔnbèi.",
      "pinyin_numeric": "ke4ren2, ke3yi3 deng3 yi1xia4 ma0? Wo3 bang1 ni3 zhun3bei4.",
      "translation_en": "Customer, could you wait a moment? I'll prepare it for you.",
      "translation_ko": "손님, 잠시만 기다려 주실 수 있나요? 제가 준비해 드릴게요."
    },
    {
      "text": "可以給我一根吸管嗎？謝謝。",
      "pinyin": "Kěyǐ gěi wǒ yī gēn xīguǎn ma? Xièxie.",
      "pinyin_numeric": "ke3yi3 gei3 wo3 yi1 gen1 xi1guan3 ma0? Xie4xie0.",
      "translation_en": "Could you give me a straw? Thank you.",
      "translation_ko": "빨대 하나 주실 수 있나요? 감사합니다."
    },
    {
      "text": "不好意思，可以再說一次價錢嗎？",
      "pinyin": "Bù hǎo yìsi, kěyǐ zài shuō yī cì jiàqián ma?",
      "pinyin_numeric": "bu4 hao3 yi4si0, ke3yi3 zai4 shuo1 yi1 ci4 jia4qian2 ma0?",
      "translation_en": "Excuse me, could you say the price again?",
      "translation_ko": "죄송합니다, 가격을 한 번 더 말씀해 주실 수 있나요?"
    },
    {
      "text": "可以幫我加珍珠嗎？我要中杯的豆漿。",
      "pinyin": "Kěyǐ bāng wǒ jiā zhēnzhū ma? Wǒ yào zhōng bēi de dòujiāng.",
      "pinyin_numeric": "ke3yi3 bang1 wo3 jia1 zhen1zhu1 ma0? Wo3 yao4 zhong1 bei1 de1 dou4jiang1.",
      "translation_en": "Could you add pearls for me? I want a medium soy milk.",
      "translation_ko": "타피오카 펄을 추가해 주실 수 있나요? 중간 컵 두유를 원해요."
    },
    {
      "text": "麻煩你，可以給我一個湯匙嗎？我要內用。",
      "pinyin": "Máfan nǐ, kěyǐ gěi wǒ yī ge tāngchí ma? Wǒ yào nèiyòng.",
      "pinyin_numeric": "ma2fan2 ni3, ke3yi3 gei3 wo3 yi1 ge0 tang1chi2 ma0? Wo3 yao4 nei4yong4.",
      "translation_en": "Excuse me, could you give me a spoon? I'll eat here.",
      "translation_ko": "실례합니다, 숟가락 하나 주실 수 있나요? 매장에서 먹을게요."
    },
    {
      "text": "可以慢一點說嗎？我聽不太懂。",
      "pinyin": "Kěyǐ màn yī diǎn shuō ma? Wǒ tīng bù tài dǒng.",
      "pinyin_numeric": "ke3yi3 man4 yi1 dian3 shuo1 ma0? Wo3 ting1 bu4 tai4 dong3.",
      "translation_en": "Could you speak a bit slower? I don't quite understand.",
      "translation_ko": "조금 천천히 말씀해 주실 수 있나요? 잘 이해가 안 돼요."
    }
  ]
}
